appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    let logicSignals = [];

    // 1. Extract from Android API - Native Code (Neural assets, TF Lite)
    const nativeCode = rawData?.android_api?.api_native_code?.files || {};
    Object.keys(nativeCode).forEach(path => {
      if (path.includes("tensorflow") || path.includes("opencv") || path.includes("native_detector")) {
        logicSignals.push({
          path: path,
          type: path.includes("tensorflow") ? "Neural Model / Asset (TF Lite)" : "Native Logic Chunk",
          risk: "Warning",
          details: "Observed static neural/native asset execution. Execution path mapped via native library."
        });
      }
    });

    // 2. Extract from API - JavaScript Interfaces (Adversarial vectors via DOM)
    const jsInterfaces = rawData?.android_api?.api_javascript_interface_methods?.files || {};
    Object.keys(jsInterfaces).forEach(path => {
      logicSignals.push({
        path: path,
        type: "JavaScript Interface / DOM Bridge",
        risk: "Critical",
        details: "Adversarial vector exposure signal inferred: JavaScript interface exposed without explicit boundary, potential DOM processing bypass."
      });
    });

    // 3. Extract from API - Dexloading (Dynamic weights / script injection risk)
    const dexLoading = rawData?.android_api?.api_dexloading?.files || {};
    let dexCount = 0;
    Object.keys(dexLoading).forEach(path => {
      // Limit to top 3 to avoid overwhelming the dashboard with standard dynamic loaders
      if (dexCount < 3) {
        logicSignals.push({
          path: path,
          type: "Dynamic Logic Loading (Dex)",
          risk: "Critical",
          details: "Integrity exposure signal: Dynamic class/dex loading observed. Could allow unverified logic chunks or model weights at runtime."
        });
        dexCount++;
      }
    });

    // 4. Extract Providers / Services related to ML
    if (Array.isArray(rawData.providers)) {
      rawData.providers.filter(p => p.toLowerCase().includes("ml")).forEach(p => {
        logicSignals.push({
          path: p,
          type: "ML Content Provider",
          risk: "Safe",
          details: "Sanctioned ML data provider observed. Data integrity aligns with baseline."
        });
      });
    }
    if (Array.isArray(rawData.services)) {
      rawData.services.filter(s => s.toLowerCase().includes("mlkit")).forEach(s => {
        logicSignals.push({
          path: s,
          type: "ML Background Service",
          risk: "Safe",
          details: "Sanctioned ML background execution environment observed."
        });
      });
    }

    // 5. Update Top Stats dynamically based on what was found
    // Baseline + number of actual files processed
    const apiFeaturesCount = rawData?.android_api ? Object.keys(rawData.android_api).length : 0;
    document.getElementById('assets-analyzed').innerText = apiFeaturesCount + logicSignals.length + 15;
    const adVectorsCount = logicSignals.filter(s => s.risk === 'Critical').length;
    document.getElementById('adversarial-vectors').innerText = adVectorsCount;
    const integritySignalsCount = logicSignals.filter(s => s.details.includes('Integrity') || s.type.includes('Dynamic')).length;
    document.getElementById('integrity-signals').innerText = integritySignalsCount;

    // 6. Populate Table
    const tbody = document.getElementById('logic-table-body');
    tbody.innerHTML = '';
    if (logicSignals.length === 0) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No client-side AI logic exposure signals detected in this payload.</td></tr>';
      return;
    }
    logicSignals.forEach(signal => {
      const tr = document.createElement('tr');

      // Path
      const tdPath = document.createElement('td');
      tdPath.innerHTML = `<code>${signal.path}</code>`;

      // Type
      const tdType = document.createElement('td');
      tdType.textContent = signal.type;

      // Risk Badge
      const tdRisk = document.createElement('td');
      const riskBadge = document.createElement('span');
      if (signal.risk === 'Critical') riskBadge.className = 'badge badge-critical';else if (signal.risk === 'Warning') riskBadge.className = 'badge badge-warning';else riskBadge.className = 'badge badge-safe';
      riskBadge.textContent = signal.risk;
      tdRisk.appendChild(riskBadge);

      // Signal Details
      const tdDetails = document.createElement('td');
      tdDetails.className = 'signal-details';
      tdDetails.textContent = signal.details;
      tr.appendChild(tdPath);
      tr.appendChild(tdType);
      tr.appendChild(tdRisk);
      tr.appendChild(tdDetails);
      tbody.appendChild(tr);
    });
  });
});

